import { Component, ViewChild, AfterViewInit,OnDestroy,OnInit, ElementRef, TemplateRef, ViewContainerRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { MatTableModule, MatTableDataSource } from '@angular/material/table';
import { MatIconModule } from '@angular/material/icon';
import { MatButtonModule } from '@angular/material/button';
import { MatSlideToggleModule } from '@angular/material/slide-toggle';
import { MatTabsModule } from '@angular/material/tabs';
import { MatInputModule } from '@angular/material/input';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatSelectModule } from '@angular/material/select';
import { MatAutocompleteModule } from '@angular/material/autocomplete';
import { MatPaginatorModule, MatPaginator } from '@angular/material/paginator';
import { MatSortModule, MatSort } from '@angular/material/sort';
import { FormsModule, ReactiveFormsModule } from '@angular/forms';
import { FormBuilder, FormGroup, FormArray } from '@angular/forms';
import { RouterModule, Router } from '@angular/router';
import { HttpClient, HttpClientModule } from '@angular/common/http';
import { API_BASE } from 'src/app/shared/api.config';
import { Overlay, OverlayRef } from '@angular/cdk/overlay';
import { TemplatePortal } from '@angular/cdk/portal';
import { LoaderService } from 'src/app/shared/services/loader.service';
import { notify } from 'src/app/shared/global-notify';
import { ConfirmService } from 'src/app/shared/services/confirm.service';
import { PageMetaService } from 'src/app/shared/services/page-meta.service';
import { OverlayModule } from '@angular/cdk/overlay';
import { PortalModule } from '@angular/cdk/portal';
import { SharedModule } from 'src/app/shared/shared.module';

export interface Institute {
  id: number;
  name: string;
  short: string;
  city?: string;
  state?: string;
  country?: string;
  active: boolean;
  primary_contact?: string;
  primary_email?: string;
  primary_contact_person?: string;
  primary_contact_email?: string;
  primary_contact_phone?: string;
  website?: string;
  max_users?: number;
  admins_count?: number;
  users_count?: number;
  industry_type?: string;
  industry_sector?: string;
  subscription_start?: string;
  subscription_end?: string;
  active_status?: boolean;
  // internal id from backend (UUID) - not shown in UI but used for actions
  institute_id?: string;
  raw?: any;
}

@Component({
  selector: 'app-view-institutes',
  standalone: true,
  imports: [CommonModule, MatTableModule, MatIconModule, SharedModule, MatButtonModule, MatSlideToggleModule, MatTabsModule, MatInputModule, MatFormFieldModule, MatSelectModule, MatAutocompleteModule, FormsModule, ReactiveFormsModule, RouterModule, MatPaginatorModule, MatSortModule, OverlayModule, PortalModule],
  templateUrl: './view-institutes.component.html',
  styleUrls: ['./view-institutes.component.scss']
})
export class ViewInstitutesComponent implements OnInit, AfterViewInit, OnDestroy {
  // Show only requested columns in list-card table (include subscription dates and active)
  columns = ['name','industry_type','industry_sector', 'primary_contact_person','subscription_start','subscription_end','active','actions'];

  filter = '';

  industryTypes = ['School', 'College', 'BPO', 'Bank', 'IT'];
  industrySectors = ['School', 'Engineering', 'Arts', 'Healthcare', 'Finance', 'Banking', 'IT'];

  // Industry -> Sector dependency map (mirrors institute-register.component.ts)
  private sectorMap: Record<string, string[]> = {
    'School': ['School'],
    'College': ['Engineering', 'Arts'],
    'BPO': ['Healthcare', 'Finance'],
    'Bank': ['Bank'],
    'IT': ['IT']
  };

  // filters
  filters: any = { name: '', industry: '', sector: '', country: '', city: '', active_status: '' };
  countries: Array<{ code: string; name: string }> = [];
  states: Array<{ code: string; name: string }> = [];
  cities: Array<{ code: string; name: string }> = [];
  instituteOptions: Array<{ id: string; name: string }> = [];
  // raw location hierarchy returned by API (countries -> states -> cities)
  private locationHierarchyRaw: any[] = [];
  // City options for the filter dropdown, scoped to the selected country via a server-side
  // location-hierarchy?country_id=... call (mirrors LocationService.getStatesForCountry).
  filterCityOptions: Array<{ code: string; name: string }> = [];

  // search terms for the searchable filter dropdowns
  countrySearch = '';
  industrySearch = '';
  sectorSearch = '';

  institutes: Institute[] = [];
  dataSource = new MatTableDataSource<Institute>([]);
  hasAppliedFilters = false;
  // keep raw response objects so detail modal can show full fields
  private rawRecords: any[] = [];

  selectedInstitute: any = null; // used for modal detail view
  showFilters = false; // control visibility of filter-block (mini modal)
  editing = false;
  editableInstitute: any = null;
  // reactive edit form to mirror the register page
  editForm: FormGroup | null = null;

  private apiUrl = `${API_BASE}/get-institutes`;

  @ViewChild(MatPaginator) paginator!: MatPaginator;
  @ViewChild(MatSort) sort!: MatSort;
  @ViewChild('filtersBtn', { read: ElementRef }) filtersBtn!: ElementRef;
  @ViewChild('filtersPanel') filtersPanelTpl!: TemplateRef<any>;

  private filtersOverlayRef: OverlayRef | null = null;
  
  constructor(private http: HttpClient, private router: Router, private loader: LoaderService, private pageMeta: PageMetaService, private overlay: Overlay, private vcr: ViewContainerRef, private confirmService: ConfirmService) {
    this.loadInstituteOptions();
    this.loadCountries();

  }

  // Helpers to resolve campus address fields into user-friendly strings
  campusAddress(cp: any): string {
    return cp?.address || cp?.address_line1 || cp?.address1 || cp?.street || cp?.address_line || '';
  }

  campusCityName(cp: any): string {
    try {
      if (!cp) return '';
      if (cp.city && typeof cp.city === 'object') return cp.city.city_name || cp.city.name || '';
      if (cp.city_name) return cp.city_name;
      const code = cp.city || cp.city_code || cp.cityId || cp.city_id || '';
      if (code) {
        if (this.cities && this.cities.length) {
          const found = this.cities.find(c => String(c.code) === String(code) || String(c.name) === String(code));
          if (found) return found.name;
        }
        const node = this.findLocationNodeById(code);
        if (node) return node.city_name || node.name || node.city || '';
      }
      return String(cp.city || cp.city_name || '');
    } catch (e) { return '' }
  }

  campusStateName(cp: any): string {
    try {
      if (!cp) return '';
      if (cp.state && typeof cp.state === 'object') return cp.state.state_name || cp.state.name || '';
      if (cp.state_name) return cp.state_name;
      const code = cp.state || cp.state_code || cp.stateId || cp.state_id || '';
      if (code) {
        if (this.states && this.states.length) {
          const found = this.states.find(s => String(s.code) === String(code) || String(s.name) === String(code));
          if (found) return found.name;
        }
        const node = this.findLocationNodeById(code);
        if (node) return node.state_name || node.name || node.state || '';
      }
      return String(cp.state || cp.state_name || '');
    } catch (e) { return '' }
  }

  campusCountryName(cp: any): string {
    try {
      if (!cp) return '';
      if (cp.country && typeof cp.country === 'object') return cp.country.country_name || cp.country.name || '';
      if (cp.country_name) return cp.country_name;
      const code = cp.country || cp.country_code || cp.countryId || cp.country_id || '';
      if (code) {
        if (this.countries && this.countries.length) {
          const found = this.countries.find(c => String(c.code) === String(code) || String(c.name) === String(code));
          if (found) return found.name;
        }
        const node = this.findLocationNodeById(code);
        if (node) return node.country_name || node.name || node.country || '';
      }
      return String(cp.country || cp.country_name || '');
    } catch (e) { return '' }
  }

  // Recursively search loaded location hierarchy for a node matching id/code/name
  private findLocationNodeById(id: any): any {
    try {
      if (!id) return null;
      const needle = String(id).toLowerCase();
      const queue = Array.isArray(this.locationHierarchyRaw) ? [...this.locationHierarchyRaw] : [];
      while (queue.length) {
        const node = queue.shift();
        if (!node) continue;
        const checks = [node.country_code, node.code, node.id, node.city_code, node.city_name, node.name, node.state_code, node.state_name, node.city, node.country, node.state];
        for (const v of checks) {
          if (v && String(v).toLowerCase() === needle) return node;
        }
        if (Array.isArray(node.states)) queue.push(...node.states);
        if (Array.isArray(node.cities)) queue.push(...node.cities);
        if (Array.isArray(node.children)) queue.push(...node.children);
      }
    } catch (e) { /* ignore */ }
    return null;
  }

  campusPostal(cp: any): string {
    return cp?.pin_code || cp?.pincode || cp?.pin || cp?.postal_code || '';
  }

  ngOnInit(): void {

    try {
      this.pageMeta.setMeta('Institutes', 'View and manage registered institutes');
    } catch (e) { /* ignore if service not available */ }
    this.restoreInstituteReturnState();
  }
  ngAfterViewInit(): void {
    try{ this.dataSource.paginator = this.paginator; this.dataSource.sort = this.sort; }catch(e){}
  }

  ngOnDestroy(): void {
  this.saveInstituteReturnState();
}

  applyFilter(value: string){
    const q = (value || '').trim().toLowerCase();
    this.dataSource.filter = q;
    if (this.dataSource.paginator) this.dataSource.paginator.firstPage();
  }

  get appliedFilterChips(): Array<{ key: string; label: string; removable: boolean }> {
    if (!this.hasAppliedFilters) return [];
    const chips: Array<{ key: string; label: string; removable: boolean }> = [];
    if (this.filters.name) chips.push({ key: 'name', label: `Institute: ${this.filters.name}`, removable: true });
    if (this.filters.industry) chips.push({ key: 'industry', label: `Industry: ${this.filters.industry}`, removable: true });
    if (this.filters.sector) chips.push({ key: 'sector', label: `Sector: ${this.filters.sector}`, removable: true });
    if (this.filters.country) chips.push({ key: 'country', label: `Country: ${this.getSelectedName(this.countries, this.filters.country, 'code')}`, removable: true });
    if (this.filters.city) chips.push({ key: 'city', label: `City: ${this.filters.city}`, removable: true });
    if (this.filters.active_status !== '') chips.push({ key: 'active_status', label: `Status: ${this.filters.active_status ? 'Active' : 'Inactive'}`, removable: true });
    return chips;
  }

  removeAppliedFilter(key: string) {
    if (!key) return;
    if (key === 'name') this.filters.name = '';
    else if (key === 'industry') { this.filters.industry = ''; this.filters.sector = ''; }
    else if (key === 'sector') this.filters.sector = '';
    else if (key === 'country') { this.filters.country = ''; this.filters.city = ''; this.filterCityOptions = []; }
    else if (key === 'city') this.filters.city = '';
    else if (key === 'active_status') this.filters.active_status = '';
    if (!this.filters.industry && !this.filters.sector) this.filters.name = '';
    this.refreshInstituteScope();
    this.refreshAfterFilterChipChange();
  }

  clearAppliedFilters() { this.resetFilters(); }
  private refreshAfterFilterChipChange() { if (this.appliedFilterChips.length) this.loadInstitutes(); else { this.hasAppliedFilters = false; this.institutes = []; this.rawRecords = []; this.dataSource.data = []; } }
  private getSelectedName(list: any[], selectedId: any, idKey: string = 'id'): string { const found = (list || []).find(item => String(item?.[idKey]) === String(selectedId)); return found?.name || String(selectedId || ''); }

  // City is now a free-text/autocomplete field holding the display name; the backend's city
  // filter expects an id, so resolve the typed/selected name back to its code here.
  private resolveCityId(cityName: string): string {
    const name = String(cityName || '').trim().toLowerCase();
    if (!name) return '';
    const pool = this.filterCityOptions.length ? this.filterCityOptions : this.cities;
    const found = pool.find(c => String(c.name || '').trim().toLowerCase() === name);
    return found ? String(found.code) : '';
  }

  loadInstitutes() {
    const params: any = {};
  if(this.filters.name) params.name = this.filters.name;
  if(this.filters.industry) params.industry = this.filters.industry;
  if(this.filters.sector) params.sector = this.filters.sector;
  if(this.filters.country) params.country = this.filters.country;
  const cityId = this.resolveCityId(this.filters.city);
  if(cityId) params.city = cityId;
    if(this.filters.active_status !== '') params.active_status = this.filters.active_status;

    this.loader.show();
    this.http.get<any>(this.apiUrl, { params }).subscribe({
      next: (res) => {
        if (res && res.data && Array.isArray(res.data)) {
          this.rawRecords = res.data;
          this.institutes = res.data.map((r: any, idx: number) => ({
            id: idx + 1,
            name: r.name,
            short: r.short_name || r.short || '',
            // prefer top-level city/state/country, fallback to first campus if present
            city: r.city || (r.campuses && r.campuses[0] && r.campuses[0].city && r.campuses[0].city.city_name) || '',
            state: r.state || (r.campuses && r.campuses[0] && r.campuses[0].state && r.campuses[0].state.state_name) || '',
            country: r.country || (r.campuses && r.campuses[0] && r.campuses[0].country && r.campuses[0].country.country_name) || '',
            primary_contact: r.primary_contact_person || '',
            primary_email: r.primary_contact_email || '',
            primary_contact_phone: r.primary_contact_phone || r.primary_contact_phone || r.primary_contact_phone || r.primary_contact_phone || '',
            website: r.website || '',
            max_users: r.max_users || null,
            admins_count: this.getAdminCount(r),
            users_count: this.getUserCount(r),
            subscription_start: r.subscription_start || r.subscriptionStart || '',
            subscription_end: r.subscription_end || r.subscriptionEnd || '',
            industry_type: r.industry_type || '',
            industry_sector: r.industry_sector || '',
            active: !!r.active_status,
            active_status: !!r.active_status,
            institute_id: r.institute_id,
            raw: r
          }));
          // update table data source
          this.dataSource.data = this.institutes;
          // set filter predicate to look into key fields
          this.dataSource.filterPredicate = (data: Institute, filter: string) => {
            const q = (filter || '').toLowerCase();
            return (data.name || '').toLowerCase().includes(q)
              || (data.short || '').toLowerCase().includes(q)
              || (data.country || '').toLowerCase().includes(q)
              || (data.city || '').toLowerCase().includes(q)
              || (data.state || '').toLowerCase().includes(q)
              || (data.industry_type || '').toLowerCase().includes(q)
              || (data.industry_sector || '').toLowerCase().includes(q);
          };
          // attach paginator/sort if available
          setTimeout(() => {
            try{ this.dataSource.paginator = this.paginator; this.dataSource.sort = this.sort; }catch(e){}
          }, 0);
        }
      },
      error: (err) => {
        console.warn('Failed to load institutes:', err);
        try{ this.loader.hide(); }catch(e){}
      },
      complete: () => { try{ this.loader.hide(); }catch(e){} }
    });
  }

  private hasFilterValues(): boolean {
    return !!(
      this.filters.name ||
      this.filters.industry ||
      this.filters.sector ||
      this.filters.country ||
      this.filters.city ||
      (this.filters.active_status !== '')
    );
  }

  applyFilters(){
    if (!this.hasFilterValues()) {
      try { notify('Please add filters in the filter form.', 'info'); } catch (e) {}
      return;
    }
    this.hasAppliedFilters = true;
    this.loadInstitutes();
    this.closeFiltersOverlay();
  }

  resetFilters(){
    this.filters = { name: '', industry: '', sector: '', country: '', city: '', active_status: '' };
    this.filter = '';
    this.dataSource.filter = '';
    this.institutes = [];
    this.rawRecords = [];
    this.dataSource.data = [];
    this.hasAppliedFilters = false;
    this.countrySearch = '';
    this.industrySearch = '';
    this.sectorSearch = '';
    this.filterCityOptions = [];
    this.loadInstituteOptions();
  }

  refresh(){
    if (!this.hasAppliedFilters) {
      try { notify('Apply filters to fetch institutes', 'info'); } catch (e) {}
      return;
    }
    this.loadInstitutes();
  }

  toggleFilters(){ this.showFilters = !this.showFilters }

  openFiltersOverlay(){
    if(!this.filtersBtn) return;
    if(this.filtersOverlayRef){ try{ this.filtersOverlayRef.dispose(); }catch(e){}; this.filtersOverlayRef = null; }

    const positionStrategy = this.overlay.position()
      .flexibleConnectedTo(this.filtersBtn)
      .withPositions([
        { originX: 'start', originY: 'bottom', overlayX: 'start', overlayY: 'top', offsetY: 8 },
        { originX: 'end', originY: 'bottom', overlayX: 'end', overlayY: 'top', offsetY: 8 }
      ])
      .withPush(true);

    this.filtersOverlayRef = this.overlay.create({ positionStrategy, hasBackdrop: true, backdropClass: 'cdk-overlay-transparent-backdrop', scrollStrategy: this.overlay.scrollStrategies.reposition() });
    this.filtersOverlayRef.backdropClick().subscribe(() => this.closeFiltersOverlay());
    this.filtersOverlayRef.keydownEvents().subscribe((ev:any) => { if(ev.key === 'Escape') this.closeFiltersOverlay(); });

    const portal = new TemplatePortal(this.filtersPanelTpl, this.vcr);
    this.filtersOverlayRef.attach(portal);
  }

  closeFiltersOverlay(){ if(this.filtersOverlayRef){ try{ this.filtersOverlayRef.dispose(); }catch(e){}; this.filtersOverlayRef = null; } }

  // country -> city filtering removed: we now load all cities in loadCountries()

  loadInstituteOptions(){
    const url = `${API_BASE}/get-institute-list`;
    this.http.get<any>(url).subscribe({
      next: (res) => {
        try {
          const data = Array.isArray(res?.data) ? res.data : [];
          this.instituteOptions = data.map((i: any) => ({
            id: i.institute_id || i.id || i._id || i.name || i.institute_name || '',
            name: i.name || i.institute_name || i.short_name || ''
          })).filter((i: any) => !!i.name);
        } catch (e) {
          this.instituteOptions = [];
        }
      },
      error: () => { this.instituteOptions = []; }
    });
  }

  filteredInstituteOptions(){
    if (!this.filters.industry && !this.filters.sector) return [];
    const q = String(this.filters.name || '').trim().toLowerCase();
    if (!q) return this.instituteOptions;
    return this.instituteOptions.filter(i => String(i.name || '').toLowerCase().includes(q));
  }

  // ---- Searchable dropdown helpers + dependent filtering ----

  get filteredCountries(): Array<{ code: string; name: string }> {
    const term = (this.countrySearch || '').trim().toLowerCase();
    if (!term) return this.countries;
    return this.countries.filter(c => (c.name || '').toLowerCase().includes(term));
  }

  // Loads cities scoped to a single country via the existing location-hierarchy?country_id=...
  // call (same endpoint/param the register page's LocationService already uses), instead of
  // filtering the entire global cities list in the browser (which is what caused the lag).
  private loadCitiesForCountry(countryCode: string) {
    if (!countryCode) { this.filterCityOptions = []; return; }
    const url = `${API_BASE}/location-hierarchy`;
    this.http.get<any>(url, { params: { country_id: countryCode } }).subscribe({
      next: (res) => {
        try {
          const data = Array.isArray(res?.data?.cities) ? res.data.cities : [];
          this.filterCityOptions = data.map((c: any) => ({ code: c.id ?? c.city_id ?? c.code, name: c.name ?? c.city_name ?? c.city }));
        } catch (e) {
          this.filterCityOptions = [];
        }
      },
      error: () => { this.filterCityOptions = []; }
    });
  }

  get filteredIndustryTypes(): string[] {
    const term = (this.industrySearch || '').trim().toLowerCase();
    if (!term) return this.industryTypes;
    return this.industryTypes.filter(t => t.toLowerCase().includes(term));
  }

  // Sectors scoped to the selected industry; empty until an industry is selected.
  private get scopedSectors(): string[] {
    const industry = this.filters.industry;
    if (!industry) return [];
    return this.sectorMap[industry] || [];
  }

  get filteredSectors(): string[] {
    const scoped = this.scopedSectors;
    const term = (this.sectorSearch || '').trim().toLowerCase();
    if (!term) return scoped;
    return scoped.filter(s => s.toLowerCase().includes(term));
  }

  onFilterSelectOpened(opened: boolean, field: 'country' | 'industry' | 'sector') {
    if (opened) {
      setTimeout(() => {
        try {
          const input = document.querySelector('.cdk-overlay-pane .select-search-input') as HTMLInputElement | null;
          input?.focus();
        } catch (e) { /* ignore non-browser environments */ }
      });
      return;
    }
    if (field === 'country') this.countrySearch = '';
    else if (field === 'industry') this.industrySearch = '';
    else if (field === 'sector') this.sectorSearch = '';
  }

  stopFilterSearchEvent(event: Event) {
    event.stopPropagation();
  }

  onCountryFilterChange() {
    this.filters.city = '';
    this.loadCitiesForCountry(this.filters.country);
    this.refreshInstituteScope();
  }

  onCityFilterChange() {
    this.refreshInstituteScope();
  }

  onIndustryFilterChange() {
    this.filters.sector = '';
    if (!this.filters.industry && !this.filters.sector) this.filters.name = '';
    this.refreshInstituteScope();
  }

  onSectorFilterChange() {
    if (!this.filters.industry && !this.filters.sector) this.filters.name = '';
    this.refreshInstituteScope();
  }

  // Reload Institute options scoped to the currently selected Country/City/Industry/Sector.
  // Falls back to the full institute list (get-institute-list) when none of those are selected.
  private refreshInstituteScope() {
    const params: any = {};
    if (this.filters.country) params.country = this.filters.country;
    const cityId = this.resolveCityId(this.filters.city);
    if (cityId) params.city = cityId;
    if (this.filters.industry) params.industry = this.filters.industry;
    if (this.filters.sector) params.sector = this.filters.sector;

    if (!Object.keys(params).length) {
      this.loadInstituteOptions();
      return;
    }

    this.http.get<any>(this.apiUrl, { params }).subscribe({
      next: (res) => {
        try {
          const data = Array.isArray(res?.data) ? res.data : [];
          this.instituteOptions = data.map((r: any) => ({
            id: r.institute_id || r.id || r._id || r.name || '',
            name: r.name || r.institute_name || r.short_name || ''
          })).filter((i: any) => !!i.name);
        } catch (e) {
          this.instituteOptions = [];
        }
        if (this.filters.name && !this.instituteOptions.some(i => i.name === this.filters.name)) {
          this.filters.name = '';
        }
      },
      error: () => { this.instituteOptions = []; }
    });
  }

  loadCountries(){
    const url = `${API_BASE}/location-hierarchy`;
  // this.loader.show();
  this.http.get<any>(url).subscribe({
      next: (res) => {
      try{
        const countries = res?.data?.countries || res?.countries || res?.data || [];
        // store raw hierarchy for recursive lookups
        this.locationHierarchyRaw = Array.isArray(countries) ? countries : [];
        // The hierarchy contains the complete world list. Keep it only for resolving
        // names/ids and populate the filter from countries used by registered institutes.
        this.loadRegisteredInstituteCountries(Array.isArray(countries) ? countries : []);
        // try to aggregate all cities from the countries payload (if present)
        let allCities: any[] = [];
        if(Array.isArray(countries)){
          countries.forEach((c:any)=>{
            if(Array.isArray(c.cities)) allCities = allCities.concat(c.cities);
            if(Array.isArray(c.states)) c.states.forEach((s:any)=>{ if(Array.isArray(s.cities)) allCities = allCities.concat(s.cities); });
            if(Array.isArray(c.children)) c.children.forEach((ch:any)=>{ if(Array.isArray(ch.cities)) allCities = allCities.concat(ch.cities); });
          });
        }
        // fallback: if API returned a top-level cities array
        if((allCities.length === 0) && (res?.data?.cities || res?.cities)){
          allCities = res?.data?.cities || res?.cities || [];
        }
        this.cities = (allCities || []).map((c:any)=> ({ code: c.city_code || c.code || c.id, name: c.city_name || c.name || c.city }));
        // also populate states array if available for lookups
        const allStates: any[] = [];
        if (Array.isArray(countries)) {
          countries.forEach((c:any)=>{
            if (Array.isArray(c.states)) allStates.push(...c.states);
            if (Array.isArray(c.children)) c.children.forEach((ch:any)=>{ if(Array.isArray(ch.states)) allStates.push(...ch.states); });
          });
        }
        this.states = (allStates || []).map((s:any) => ({ code: s.state_code || s.code || s.id, name: s.state_name || s.name || s.state }));
      }catch(e){ this.countries = []; this.cities = []; }
    },
    error: () => { this.countries = []; this.cities = [];  },
    complete: () => { }
  });
  }

  private loadRegisteredInstituteCountries(locationCountries: any[]) {
    this.countries = [];
    this.http.get<any>(this.apiUrl).subscribe({
      next: (res) => {
        try {
          const institutes = Array.isArray(res?.data) ? res.data : [];
          const hierarchyCountries = locationCountries.map((country: any) => ({
            code: country.country_code || country.code || country.id,
            name: country.country_name || country.name || country.country
          })).filter((country: any) => country.code && country.name);
          const registeredCountries: Array<{ code: string; name: string }> = [];
          institutes.forEach((institute: any) => {
            const locations = [institute, ...(Array.isArray(institute?.campuses) ? institute.campuses : [])];
            locations.forEach((location: any) => {
              const rawCountry = location?.country;
              const countryCode = location?.country_id || location?.country_code
                || (typeof rawCountry === 'object' ? rawCountry?.country_id || rawCountry?.id || rawCountry?.country_code || rawCountry?.code : rawCountry);
              const countryName = location?.country_name
                || (typeof rawCountry === 'object' ? rawCountry?.country_name || rawCountry?.name || rawCountry?.country : rawCountry);
              const hierarchyMatch = hierarchyCountries.find((country: any) =>
                (countryCode && String(country.code).toLowerCase() === String(countryCode).toLowerCase())
                || (countryName && String(country.name).trim().toLowerCase() === String(countryName).trim().toLowerCase())
              );
              const resolved = hierarchyMatch || (countryCode && countryName ? { code: countryCode, name: countryName } : null);
              if (resolved) registeredCountries.push({ code: String(resolved.code), name: String(resolved.name).trim() });
            });
          });
          const uniqueByName = new Map<string, { code: string; name: string }>();
          registeredCountries.forEach(country => {
            const key = country.name.toLowerCase();
            if (!uniqueByName.has(key)) uniqueByName.set(key, country);
          });
          this.countries = Array.from(uniqueByName.values()).sort((a, b) => a.name.localeCompare(b.name));
        } catch (e) {
          this.countries = [];
        }
      },
      error: () => { this.countries = []; }
    });
  }
  // country/state/city filters removed for Institutes view; helpers left intentionally blank

  get filtered() {
    const q = this.filter && this.filter.toLowerCase();
    if (!q) return this.institutes;
    return this.institutes.filter(i => i.name.toLowerCase().includes(q)
      || (i.short||'').toLowerCase().includes(q)
      || (i.country||'').toLowerCase().includes(q)
      || (i.city||'').toLowerCase().includes(q)
      || (i.state||'').toLowerCase().includes(q)
      || (i.industry_type||'').toLowerCase().includes(q)
      || (i.industry_sector||'').toLowerCase().includes(q)
    );
  }

  toggleActive(i: Institute){
    const previous = !!i.active;
    const newState = !previous;
    const actionVerb = newState ? 'activate' : 'deactivate';
    const confirmMessage = `Are you sure you want to ${actionVerb} institute "${i.name}"?`;
    // show confirmation dialog using ConfirmService
    try {
      this.confirmService.confirm({ title: 'Confirm', message: confirmMessage, confirmText: 'Yes', cancelText: 'No' }).subscribe((ok) => {
        if (!ok) return;

        // optimistic update for responsiveness
        i.active = newState;
        const action = i.active ? 'activate' : 'deactivate';
        const uuid = i.institute_id || (i.raw && (i.raw.institute_id || i.raw.id || i.raw._id));
        if(!uuid){
          console.warn('No institute id present for toggleActive');
          // revert
          i.active = previous;
          return;
        }
        const url = `${API_BASE}/institute/${action}/${uuid}`;
        // include current user id in body
        let current_user_id: any = null;
        try{
          const raw = sessionStorage.getItem('user') || sessionStorage.getItem('user_profile');
          if(raw) {
            const obj = JSON.parse(raw);
            current_user_id = obj.user_id || obj.id || null;
          }
        }catch(e){ current_user_id = null; }
        const body: any = { current_user: current_user_id };
        try{ this.loader.show(); }catch(e){}
        this.http.put(url, body, { observe: 'response' }).subscribe({
          next: (res) => {
            try{ this.loader.hide(); }catch(e){}
            try { notify(`Institute ${i.name} ${action}d successfully`, 'success'); } catch (e) {}
          },
          error: (err) => {
            try{ this.loader.hide(); }catch(e){}
            console.error('Failed to toggle institute active state', err);
            // revert
            i.active = previous;
            try { notify('Failed to change institute status. Please try again.', 'error'); } catch (e) {}
          }
        });
      });
      return;
    } catch (e) { return; }
  }

  viewDetails(i: Institute){
    // keep the backend institute_id in storage for feature development, but don't show it in UI
    const payload = { ...i };
    try { sessionStorage.setItem('view_institute', JSON.stringify(payload)); } catch(e){}
    // open detail modal
    this.selectedInstitute = i.raw || i;
  }

  getAdminCount(institute: any): number {
    return this.resolveCount(
      institute,
      ['admins_count', 'admin_count', 'total_admins', 'totalAdmins', 'adminCount', 'adminsCount', 'number_of_admins', 'no_of_admins'],
      ['admins', 'admin_users', 'adminUsers', 'institute_admins', 'instituteAdmins']
    );
  }

  getUserCount(institute: any): number {
    return this.resolveCount(
      institute,
      ['users_count', 'user_count', 'total_users', 'totalUsers', 'userCount', 'usersCount', 'number_of_users', 'no_of_users'],
      ['users', 'institute_users', 'instituteUsers']
    );
  }

  private resolveCount(institute: any, countKeys: string[], collectionKeys: string[]): number {
    if (!institute) return 0;

    for (const key of countKeys) {
      const value = institute[key];
      if (value !== undefined && value !== null && value !== '') {
        const count = Number(value);
        return Number.isFinite(count) ? count : 0;
      }
    }

    for (const key of collectionKeys) {
      const value = institute[key];
      if (Array.isArray(value)) return value.length;
    }

    return 0;
  }

  startEdit(i: Institute){
    // Redirect to the institute-register page and prefill the form from storage
    try {
      const raw = i.raw || i || {};
      const payload: any = { ...raw };
      // Normalize subscription dates to YYYY-MM-DD strings so date inputs display correctly
      const fmt = (val: any) => {
        if (!val && val !== 0) return '';
        try {
          // If it's already a Date
          if (val instanceof Date) return val.toISOString().slice(0,10);
          // Try parsing ISO / timestamp strings
          const d = new Date(String(val));
          if (!isNaN(d.getTime())) return d.toISOString().slice(0,10);
          // Try to extract YYYY-MM-DD from common formats
          const m = String(val).match(/(\d{4}-\d{2}-\d{2})/);
          if (m) return m[1];
          const m2 = String(val).match(/(\d{2}\/\d{2}\/\d{4})/);
          if (m2) {
            // convert DD/MM/YYYY or MM/DD/YYYY guess to YYYY-MM-DD (try both)
            const parts = m2[1].split(/\//);
            // assume DD/MM/YYYY
            return `${parts[2]}-${parts[1].padStart(2,'0')}-${parts[0].padStart(2,'0')}`;
          }
        } catch(e) {}
        return '';
      };
      try { payload.subscription_start = fmt(raw.subscription_start || raw.subscriptionStart || ''); } catch(e) { payload.subscription_start = ''; }
      try { payload.subscription_end = fmt(raw.subscription_end || raw.subscriptionEnd || ''); } catch(e) { payload.subscription_end = ''; }
      sessionStorage.setItem('edit_institute', JSON.stringify(payload));
    } catch(e) {}
    this.saveInstituteReturnState();
    this.router.navigate(['/institute-register']);
    return;
    // build a reactive edit form mirroring the register form for consistent UX
    try{
      const fb = new FormBuilder();
      this.editForm = fb.group({
        name: [this.editableInstitute.name || ''],
        short_name: [this.editableInstitute.short_name || this.editableInstitute.short || ''],
        industry_type: [this.editableInstitute.industry_type || ''],
        industry_sector: [this.editableInstitute.industry_sector || ''],
        primary_contact_person: [this.editableInstitute.primary_contact_person || ''],
        primary_contact_email: [this.editableInstitute.primary_contact_email || ''],
        primary_contact_phone: [this.editableInstitute.primary_contact_phone || ''],
        website: [this.editableInstitute.website || ''],
        max_users: [this.editableInstitute.max_users || null],
        subscription_start: [this.editableInstitute.subscription_start || ''],
        subscription_end: [this.editableInstitute.subscription_end || ''],
        active_status: [!!this.editableInstitute.active_status]
      });
    }catch(e){ this.editForm = null; }
    // prepare CSV/JSON helper fields for editing complex arrays
    try{
      this.editableInstitute._departmentsCsv = (this.editableInstitute.departments && Array.isArray(this.editableInstitute.departments)) ? this.editableInstitute.departments.map((d:any)=> d && d.name ? d.name : (typeof d === 'string' ? d : '')).join(',') : '';
    }catch(e){ this.editableInstitute._departmentsCsv = ''; }
    try{
      this.editableInstitute._teamsCsv = (this.editableInstitute.teams && Array.isArray(this.editableInstitute.teams)) ? this.editableInstitute.teams.map((t:any)=> t && t.name ? t.name : (typeof t === 'string' ? t : '')).join(',') : '';
    }catch(e){ this.editableInstitute._teamsCsv = ''; }
    try{
      this.editableInstitute._campusesJson = JSON.stringify(this.editableInstitute.campuses || [], null, 2);
    }catch(e){ this.editableInstitute._campusesJson = '[]'; }
  }

  confirmDelete(i: Institute){
    try {
      this.confirmService.confirm({ title: 'Confirm Delete', message: `Are you sure you want to delete institute "${i.name}"? This action cannot be undone.`, confirmText: 'Delete', cancelText: 'Cancel' }).subscribe((ok) => {
        if (!ok) return;
        const uuid = i.institute_id || (i.raw && (i.raw.institute_id || i.raw.id || i.raw._id));
        if(!uuid){
          // remove locally if no uuid
          this.institutes = this.institutes.filter(x => x.id !== i.id);
          try { notify('Institute removed locally', 'info'); } catch (e) {}
          return;
        }
        const url = `${API_BASE}/delete/institute/${uuid}`;
        try{ this.loader.show(); }catch(e){}
        this.http.delete<any>(url, { observe: 'response' }).subscribe({
          next: (res) => {
            try{ this.loader.hide(); }catch(e){}
            // remove from list
            this.institutes = this.institutes.filter(x => x.institute_id !== uuid && x.id !== i.id);
            try { notify('Institute deleted successfully', 'success'); } catch (e) {}
            if (this.hasAppliedFilters) this.loadInstitutes();
          },
          error: (err) => {
            try{ this.loader.hide(); }catch(e){}
            console.error('Failed to delete institute', err);
            // Common failure: network disconnected or backend unreachable (status 0)
            try {
              if (err && (err.status === 0 || err.status === 502 || err.status === 503)) {
                notify('Network error: cannot reach backend. Check server and network connection.', 'error');
              } else {
                notify('Failed to delete institute. Please try again later.', 'error');
              }
            } catch (e) {}
          }
        });
      });
    } catch (e) { return; }
  }

  closeModal(){ this.selectedInstitute = null; this.editing = false; this.editableInstitute = null }

  saveEdit(){
    if(!this.editableInstitute) return;
    // if editForm exists, ensure it's valid before proceeding
    if (this.editForm && this.editForm.invalid) {
      try { notify('Please correct errors in the edit form before saving.', 'error'); } catch(e){}
      return;
    }
    // apply locally to institutes list; backend save TODO
    const idx = this.institutes.findIndex(x => x.institute_id === this.editableInstitute.institute_id || x.id === this.editableInstitute.id);
    if(idx >= 0){
      // merge: update displayed columns and raw object with full edited payload
      const raw = this.editableInstitute;
      // if a reactive editForm exists, prefer its values (keeps validation/formatting consistent)
      if (this.editForm) {
        const fv = this.editForm.value;
        raw.name = fv.name; raw.short_name = fv.short_name; raw.industry_type = fv.industry_type; raw.industry_sector = fv.industry_sector;
        raw.primary_contact_person = fv.primary_contact_person; raw.primary_contact_email = fv.primary_contact_email; raw.primary_contact_phone = fv.primary_contact_phone;
        raw.website = fv.website; raw.max_users = fv.max_users; raw.subscription_start = fv.subscription_start; raw.subscription_end = fv.subscription_end; raw.active_status = !!fv.active_status;
      }
      // if CSV/JSON helper fields were edited, reconcile them into raw arrays
      if(raw._departmentsCsv !== undefined){
        const parts = (raw._departmentsCsv || '').split(',').map((s: string) => s.trim()).filter(Boolean);
        raw.departments = parts.map((p: string) => ({ name: p }));
      }
      if(raw._teamsCsv !== undefined){
        const parts = (raw._teamsCsv || '').split(',').map((s: string) => s.trim()).filter(Boolean);
        raw.teams = parts.map((p: string) => ({ name: p }));
      }
      if(raw._campusesJson !== undefined){
        try{
          const parsed = JSON.parse(raw._campusesJson || '[]');
          raw.campuses = Array.isArray(parsed) ? parsed : raw.campuses;
        }catch(e){
          // keep existing campuses if JSON invalid
        }
      }
      this.institutes[idx] = {
        ...this.institutes[idx],
  name: raw.name,
        short: raw.short_name || raw.short || '',
        city: raw.city || (raw.campuses && raw.campuses[0] && raw.campuses[0].city && raw.campuses[0].city.city_name) || '',
        state: raw.state || (raw.campuses && raw.campuses[0] && raw.campuses[0].state && raw.campuses[0].state.state_name) || '',
        country: raw.country || (raw.campuses && raw.campuses[0] && raw.campuses[0].country && raw.campuses[0].country.country_name) || '',
  primary_contact: raw.primary_contact_person || raw.primary_contact || '',
  primary_email: raw.primary_contact_email || '',
  primary_contact_phone: raw.primary_contact_phone || raw.primary_contact_phone || '',
        website: raw.website || '',
        max_users: raw.max_users || null,
        industry_type: raw.industry_type || '',
        industry_sector: raw.industry_sector || '',
        active: !!raw.active_status,
        raw: raw
      } as Institute;
    }
    this.closeModal();
  }
  openInstituteRegister(): void {
    this.saveInstituteReturnState();
    this.router.navigate(['/institute-register']);
  }

  saveInstituteReturnState(): void {
    try {
      sessionStorage.setItem('institute_return_state', JSON.stringify({
        filter: this.filter,
        filters: this.filters,
        hasAppliedFilters: this.hasAppliedFilters,
        institutes: this.institutes,
        rawRecords: this.rawRecords
      }));
    } catch (e) { }
  }

  private restoreInstituteReturnState(): void {
    try {
      const raw = sessionStorage.getItem('institute_return_state');
      if (!raw) return;
      sessionStorage.removeItem('institute_return_state');
      const state = JSON.parse(raw);
      this.filter = state?.filter || '';
      this.filters = state?.filters || this.filters;
      this.hasAppliedFilters = !!state?.hasAppliedFilters;
      this.institutes = Array.isArray(state?.institutes) ? state.institutes : [];
      this.rawRecords = Array.isArray(state?.rawRecords) ? state.rawRecords : [];
      this.dataSource.data = this.institutes;
      this.applyFilter(this.filter || '');
    } catch (e) {
      try { sessionStorage.removeItem('institute_return_state'); } catch (_) { }
    }
  }
}
